import{_ as e,c as t,o as p,d as r}from"./app.f1e4bbc1.js";const l='{"title":"\u0410\u0440\u0442-\u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442 \u041D\u043E\u0432\u044B\u0439 \u0432\u044B\u0437\u043E\u0432","description":"","frontmatter":{"title":"\u0410\u0440\u0442-\u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442 \u041D\u043E\u0432\u044B\u0439 \u0432\u044B\u0437\u043E\u0432","date":"2016-06-08","cover":"cover1-1.jpg","youtube":"https://youtu.be/tD-T4LIddtE"},"headers":[],"relativePath":"theory/research/art-manifest-novyj-vyzov/index.md"}',a={},o=r('<p>\u041D\u0430\u0441\u0442\u0430\u043B\u043E \u0432\u0440\u0435\u043C\u044F, \u043A\u043E\u0433\u0434\u0430 \u043D\u0430\u043C \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0430\u043C \u043F\u043E\u0440\u0430\xA0\u043F\u0440\u0435\u043A\u0440\u0430\u0442\u0438\u0442\u044C \u043F\u0438\u0442\u0430\u0442\u044C \u043B\u043E\u0436\u043D\u044B\u0435 \u043D\u0430\u0434\u0435\u0436\u0434\u044B \u0438 \u0441\u043C\u0438\u0440\u0438\u0442\u044C\u0441\u044F \u0441 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u043E\u0441\u0442\u0440\u0435\u043D\u0438\u0435\u043C \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0432 \u0441\u0444\u0435\u0440\u0435 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0430. \u041C\u044B \u0434\u043E\u043B\u0436\u043D\u044B \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0438\u0442\u044C\u0441\u044F \u0438 \u0431\u0440\u043E\u0441\u0438\u0442\u044C \u0432\u044B\u0437\u043E\u0432 \u0441\u043B\u043E\u0436\u0438\u0432\u0448\u0438\u043C\u0441\u044F \u0441\u043E\u0433\u043B\u0430\u0448\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0432\u0440\u0435\u043C\u044F \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044E\u0442 \u0432\u0441\u044E \u043D\u0430\u0448\u0443 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u0443. \u041C\u044B \u0441\u0430\u043C\u0438 \u0434\u043E\u043B\u0436\u043D\u044B \u0434\u0430\u0442\u044C \u0442\u043E\u043B\u0447\u043E\u043A \u043A \u0440\u0435\u0448\u0435\u043D\u0438\u044E \u043F\u0440\u043E\u0431\u043B\u0435\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0442\u043E\u044F\u0442 \u043F\u0435\u0440\u0435\u0434 \u043D\u0430\u043C\u0438 \u0441\u0435\u0433\u043E\u0434\u043D\u044F.</p><p>\u041F\u043E\u0441\u043B\u0435 \u0434\u043E\u043B\u0433\u0438\u0445 \u0434\u0435\u0431\u0430\u0442\u043E\u0432, \u043E\u043F\u0440\u043E\u0441\u043E\u0432 \u0438 \u043E\u0431\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u0439 \u043C\u044B \u0432\u044B\u0434\u0432\u0438\u043D\u0443\u043B\u0438 \u044D\u0442\u043E\u0442 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442 \u0438 \u0432\u044B\u0437\u043E\u0432.</p><p>\u041C\u044B \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u043C, \u0447\u0442\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u043D\u0435\u043F\u0440\u0435\u043A\u043B\u043E\u043D\u043D\u043E\u0439 \u0432\u0435\u0440\u044B \u0432 \u0441\u0435\u0431\u044F \u043D\u0438 \u043E\u0434\u0438\u043D \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0432\u044B\u0436\u0438\u0442\u044C \u0438 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u0431\u0435\u0437 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0438 \u043A\u0430\u043A \u0435\u0433\u043E / \u0435\u0435 \u043A\u043E\u043B\u043B\u0435\u0433 \u0442\u0430\u043A \u0438 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438.</p><p>\u041C\u044B \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u043C, \u0447\u0442\u043E \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 \u043F\u043E\u0440\u044F\u0434\u043E\u043A \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u043F\u043E\u043B\u043D\u043E\u043C\u043E\u0447\u0438\u044F\u043C\u0438 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0442\u044C \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u043D\u0430\u0434 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0438, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u043C\u0438 \u0434\u043B\u044F \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u044B\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u0438 \u0440\u043E\u0441\u0442\u0430, \u0432 \u0442\u043E\u043C \u0447\u0438\u0441\u043B\u0435 \u0432 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u0445 \u043C\u0430\u0441\u0441\u043E\u0432\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438, \u0447\u044C\u0435 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0441\u0432\u0435\u0434\u0435\u043D\u0438\u0439 \u0438\u043B\u0438 \u043F\u0440\u043E\u043F\u0430\u0433\u0430\u043D\u0434\u0430 \xA0\u0440\u0435\u0437\u043A\u043E \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043C\u043D\u0435\u043D\u0438\u0435 \u0438 \u0432 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0443. \u041C\u044B \u0431\u0440\u043E\u0441\u0430\u0435\u043C \u0432\u044B\u0437\u043E\u0432 \u044D\u0442\u043E\u043C\u0443 \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0438 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u043C \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u0431\u043E\u0441\u043D\u043E\u0432\u044B\u0432\u0430\u044E\u0442 \u0435\u0433\u043E!</p><p>\u041C\u044B \u0431\u0440\u043E\u0441\u0430\u0435\u043C \u0432\u044B\u0437\u043E\u0432 \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044E \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u0437\u0432\u0430\u043D\u0438\u0435 \u0432 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0435, \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435, \u0434\u043E\u043B\u0436\u043D\u043E\u0441\u0442\u044C, \u0438\u043B\u0438 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0439 \u0443\u0441\u043F\u0435\u0445 \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0443\u0437\u0430\u043A\u043E\u043D\u0438\u0432\u0430\u044E\u0442 \u0443\u0441\u0438\u043B\u0438\u044F \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0430, \u043C\u043D\u0435\u043D\u0438\u044F, \u043A\u0440\u0438\u0442\u0438\u043A\u0443 \u0438\u043B\u0438 \u0434\u0430\u044E\u0442 \u0434\u043E\u0432\u0435\u0440\u0438\u0435 \u043A \u0440\u0430\u0431\u043E\u0442\u0435 \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0430!</p><p>\u041C\u044B \u0431\u0440\u043E\u0441\u0430\u0435\u043C \u0432\u044B\u0437\u043E\u0432 \u043F\u0440\u0435\u043C\u0438\u0430\u043B\u044C\u043D\u044B\u043C \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C \u0441 \u0438\u0445 \u0441\u0430\u043C\u043E\u0434\u043E\u0432\u043E\u043B\u044C\u043D\u044B\u043C \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u0435\u043D\u0438\u0435\u043C, \u0441\u043F\u043E\u0441\u043E\u0431\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u044E \u043B\u043E\u0436\u043D\u043E\u0433\u043E \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F, \u0447\u0442\u043E \u0437\u0430\u0432\u043E\u0435\u0432\u0430\u043D\u0438\u0435 \u043D\u0430\u0433\u0440\u0430\u0434, \u043F\u0440\u0435\u043C\u0438\u0439, \u0433\u0440\u0430\u043D\u0442\u043E\u0432 \u0438 \u0442.\u0434. \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u0438\u0434\u0430\u0435\u0442 \u0441\u0438\u043B\u0443 \u0440\u0430\u0431\u043E\u0442\u0435, \u0434\u043E\u043B\u0436\u043D\u043E\u0441\u0442\u0438, \u043A\u0440\u0438\u0442\u0438\u043A\u0435 \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0430 \u0438\u043B\u0438 \u043C\u043D\u0435\u043D\u0438\u044F\u043C \u043E \u043D\u0435\u043C.</p><p>\u041C\u044B \u0431\u0440\u043E\u0441\u0430\u0435\u043C \u0432\u044B\u0437\u043E\u0432 \u0448\u0438\u0440\u043E\u043A\u043E \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u043D\u043E\u0439 \xA0\u0442\u043E\u0447\u043A\u0435 \u0437\u0440\u0435\u043D\u0438\u044F, \u0447\u0442\u043E \u043F\u043E\u043B\u043D\u0430\u044F, \u043D\u0435\u043E\u0431\u0443\u0437\u0434\u0430\u043D\u043D\u0430\u044F, \u043D\u0435 \u043F\u043E\u0434\u043B\u0435\u0436\u0430\u0449\u0430\u044F \u0446\u0435\u043D\u0437\u0443\u0440\u0435 \u0441\u0432\u043E\u0431\u043E\u0434\u0430 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 \u0431\u0435\u0437\u0434\u0430\u0440\u0449\u0438\u043D\u0443 \u0438 \u0447\u0442\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0438\u0437 \u0440\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0439. \u042D\u0442\u043E \u043D\u0435 \u0442\u0430\u043A! \u0418\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u043E \u0437\u0430\u0434\u044B\u0445\u0430\u0435\u0442\u0441\u044F \u0438 \u0441\u0442\u0430\u0433\u043D\u0438\u0440\u0443\u0435\u0442 \u043F\u043E\u0434 \u0440\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F\u043C\u0438, \u0431\u0443\u0434\u044C \u043E\u043D\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0435 \u043F\u043E\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0438\u043B\u0438 \u0441\u043A\u0440\u044B\u0442\u044B\u0435\xA0\u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u0435. \u0418\u0441\u0442\u043E\u0440\u0438\u0447\u0435\u0441\u043A\u0438\xA0\u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u043B\u044E\u0434\u0438 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0430 \u0431\u0435\u0433\u0443\u0442\xA0\u0438\u0437 \u0440\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0432\u043D\u044B\u0445 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432 \u0432 \u0431\u043E\u043B\u0435\u0435 \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u0435 \u0434\u043B\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0433\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0438\u0434\u0435\u0439. \u041D\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0430 \u043A \u043D\u0435\u043E\u0431\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u043F\u043E\u0437\u0438\u0446\u0438\u0438 \u043D\u0435\u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u043E\u0441\u0442\u0438 \u0438\u043B\u0438 \u0431\u0435\u0434\u043D\u043E\u0441\u0442\u0438 \u043B\u044E\u0431\u043E\u0439 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0434\u043D\u043E\u0439 \u0438\u0437 \u0444\u043E\u0440\u043C \u0440\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0439 \u0438 \u044D\u0442\u043E\u043C\u0443 \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0431\u0440\u043E\u0448\u0435\u043D \u0432\u044B\u0437\u043E\u0432.</p><p>\u041C\u044B \u0431\u0440\u043E\u0441\u0430\u0435\u043C \u0432\u044B\u0437\u043E\u0432 \u043F\u0440\u0438\u0441\u0442\u0440\u0430\u0441\u0442\u043D\u044B\u043C \u043C\u0430\u0445\u0438\u043D\u0430\u0446\u0438\u044F\u043C \u0438\u0435\u0440\u0430\u0440\u0445\u0438\u0447\u0435\u0441\u043A\u0438 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0445 \u043C\u0435\u0436\u0434\u0443 \u0441\u043E\u0431\u043E\u0439 \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0439, \u043A\u0440\u0443\u0436\u043A\u043E\u0432, \u0433\u0430\u043B\u0435\u0440\u0435\u0439, \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u043E\u0432\u0435\u0442\u043E\u0432, \u0438\u0437\u0434\u0430\u043D\u0438\u0439, \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0448\u043A\u043E\u043B \u0438 \u043C\u0443\u0437\u0435\u0435\u0432. \u041E\u0442 \u043D\u0438\u0445 \u0440\u0430\u0437\u0438\u0442 \u0444\u0430\u0432\u043E\u0440\u0438\u0442\u0438\u0437\u043C\u043E\u043C!</p><p>\u041C\u044B \u0441\u0442\u0430\u0432\u0438\u043C \u043F\u043E\u0434 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0435 \u0441\u043F\u0440\u0430\u0432\u0435\u0434\u043B\u0438\u0432\u043E\u0441\u0442\u044C \u043C\u0435\u0442\u043E\u0434\u043E\u0432 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u043D\u0430 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u043E, \u0438 \u043C\u044B \u0431\u0440\u043E\u0441\u0430\u0435\u043C \u0432\u044B\u0437\u043E\u0432 \u043F\u0440\u0430\u0432\u0443 \u0438 \u043F\u0440\u0438\u0432\u0438\u043B\u0435\u0433\u0438\u044F\u043C \u043D\u0430 \u0434\u0438\u0441\u043A\u0440\u0438\u043C\u0430\u0446\u0438\u044E \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u043E\u0432 \u043B\u044E\u0431\u044B\u043C \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0443\u0447\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u0435\u043C, \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0438\u043B\u0438 \u0447\u0430\u0441\u0442\u043D\u044B\u043C, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0443 \u043A\u0430\u043A \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0447\u0435\u0440\u0435\u0437 \u0433\u0440\u0430\u043D\u0442\u044B, \u0442\u0430\u043A \u0438 \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E \u0447\u0435\u0440\u0435\u0437 \u0441\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u043D\u0430\u043B\u043E\u0433\u043E\u0432.</p><p>\u041C\u044B \u0431\u0440\u043E\u0441\u0430\u0435\u043C \u0432\u044B\u0437\u043E\u0432 \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u043C\u0443 \u0430\u043A\u0446\u0435\u043D\u0442\u0443 \u043D\u0430 \u0442\u0435\u0445\u043D\u0438\u043A\u0435 \u0438 \u043F\u0440\u0438\u0451\u043C\u0430\u0445, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u0442\u0430\u043B \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0438\u043C \u0438 \u0438\u0437\u043D\u0443\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u0444\u0430\u043A\u0442\u043E\u0440\u043E\u043C \u0432 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0435 \u0438 \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0442\u0430\u043A\u0436\u0435 \u0441\u0442\u0430\u043B \u0433\u043B\u0430\u0432\u043D\u044B\u043C \u043A\u0440\u0438\u0442\u0435\u0440\u0438\u0435\u043C \u0441\u0443\u0436\u0434\u0435\u043D\u0438\u0439 \u043E \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0438.</p><p>\u0418\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u043E \u0432\u044B\u043D\u0443\u0436\u0434\u0435\u043D\u043D\u043E \u043F\u0435\u0440\u0435\u0441\u0442\u0430\u043B\u043E \u0431\u044B\u0442\u044C \u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u043E\u0439 \u0447\u0430\u0441\u0442\u044C\u044E \u043D\u0430\u0448\u0435\u0433\u043E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u0438 \u0431\u044B\u043B\u043E \u043D\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043E \u0434\u043E \u043F\u0440\u043E\u0441\u0442\u044B\u0445 \u0442\u0435\u0445\u043D\u0438\u043A, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0438\u0432\u0435\u043B\u0438 \u043A \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0443 \u0441\u0443\u0445\u0438\u0445, \u0430\u043A\u0430\u0434\u0435\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u0445, \u043F\u0435\u0434\u0430\u043D\u0442\u0438\u0447\u043D\u044B\u0445, \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u043D\u044B\u0445, \u043C\u0435\u0445\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u0439 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0430 \u043C\u0430\u0441\u0441\u043E\u0432\u043E\u0433\u043E \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0430, \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u0445 \u0432\u0441\u044F\u043A\u043E\u0439 \u0446\u0435\u043B\u043E\u0441\u0442\u043D\u043E\u0441\u0442\u0438, \u0447\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u0438 \u0438 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F.\xA0\u0418\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u043E \u043E\u043A\u0430\u0437\u0430\u043B\u043E\u0441\u044C \u043B\u0438\u0448\u0435\u043D\u043E \u0435\u0433\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E, \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E, \u043D\u0440\u0430\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0438 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0433\u043E \u0434\u043B\u044F \u043F\u0440\u043E\u0446\u0432\u0435\u0442\u0430\u043D\u0438\u044F \u0438, \u043F\u043E \u0441\u0443\u0442\u0438, \u0441\u0430\u043C\u043E\u0433\u043E \u0432\u044B\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0439 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B.</p><p>\u0418\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0443 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043F\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u043E \u0431\u0435\u0441\u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u043F\u0440\u043E\u0446\u0432\u0435\u0442\u0430\u0442\u044C \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0434\u043D\u043E\u0439 \u0438\u0437 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0445 \u043E\u0431\u043B\u0430\u0441\u0442\u0435\u0439 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B, \u0433\u0434\u0435 \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442 \u0441\u0432\u043E\u044E \u0434\u0443\u0445\u043E\u0432\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443.</p><p>\u041F\u043E\u0434\u043F\u0438\u0441\u0430\u043D\u043E: <em>\u0421\u0442\u0438\u0432\u0435\u043D \u042D\u043C\u043C\u0430</em> <em>\u041C\u0430\u0440\u0442\u0430 \u0414\u0435\u043C\u043F\u0441\u0442\u0435\u0440</em> <em>\u0423\u043C\u0431\u0435\u0440\u0442\u043E \u041A\u0440\u0435\u043D\u043A\u0430</em></p><p>14 \u0430\u043F\u0440\u0435\u043B\u044F 1982 \u0433.</p><hr><p>\u0423\u043C\u0431\u0435\u0440\u0442\u043E \u041A\u0440\u0435\u043D\u043A\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u043C <a href="/theory/research/as220/">AS220, \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u0432 \u0440\u0430\u0439\u043E\u043D\u0435 \u0414\u0430\u0443\u043D\u0442\u0430\u0443\u043D \u0433\u043E\u0440\u043E\u0434\u0430 \u041F\u0440\u043E\u0432\u0438\u0434\u0435\u043D\u0441, \u0432 \u0448\u0442\u0430\u0442\u0435 \u0420\u043E\u0434-\u0410\u0439\u043B\u0435\u043D\u0434, \u0421\u0428\u0410</a>. AS220 \u043D\u0430\u0447\u0430\u043B\u0430\u0441\u044C \u0441 \u043E\u0434\u043D\u043E\u0433\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430 \u0438 $800. \u041C\u0430\u043D\u0438\u0444\u0435\u0441\u0442 \u0431\u044B\u043B \u043D\u0430\u043F\u0438\u0441\u0430\u043D \u0421\u0442\u0438\u0432\u0435\u043D\u043E\u043C \u042D\u043C\u043C\u043E\u0439 \u0432 1982 \u0433\u043E\u0434\u0443 \u0432 \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u0435 \u0441 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u043E\u0432, \u0432 \u0447\u0438\u0441\u043B\u0435 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0431\u044B\u043B\u0438 \u0434\u0432\u0430 \u0434\u0440\u0443\u0433\u0438\u0445 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430, \u043F\u043E\u0434\u043F\u0438\u0441\u0430\u0432\u0448\u0438\u0445 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442: \u0423\u043C\u0431\u0435\u0440\u0442\u043E \u041A\u0440\u0435\u043D\u043A\u0430 \u0438 \u041C\u0430\u0440\u0442\u0430 \u0414\u0435\u043C\u043F\u0441\u0442\u0435\u0440. \u041C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u0447\u0442\u043E \u043C\u043D\u043E\u0433\u043E\u0435 \u0438\u0437\u043C\u0435\u043D\u0438\u043B\u043E\u0441\u044C \u0441 \u0442\u0435\u0445 \u0432\u043E\u043B\u044C\u043D\u044B\u0445\xA0\u0434\u043D\u0435\u0439, \u043D\u043E \u0438\u0434\u0435\u0430\u043B\u044B \u044D\u0442\u043E\u0433\u043E \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430 \u0434\u043E \u0441\u0438\u0445 \u043F\u043E\u0440 \u0430\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u044B.</p>',16),_=[o];function s(c,n,d,i,m,h){return p(),t("div",null,_)}var u=e(a,[["render",s]]);export{l as __pageData,u as default};
